using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;

namespace ContosoUniversity.Tests.Helpers
{
    public static class ControllerTestHelper
    {
        public static void SetupController(Controller controller)
        {
            var httpContext = new DefaultHttpContext();
            var tempData = new TempDataDictionary(httpContext, Mock.Of<ITempDataProvider>());

            controller.ControllerContext = new ControllerContext
            {
                HttpContext = httpContext
            };
            controller.TempData = tempData;
        }

        public static IFormFile CreateMockFormFile(string fileName, long size, byte[]? content = null)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.Length).Returns(size);
            mock.Setup(f => f.ContentType).Returns("image/jpeg");

            if (content != null)
            {
                var ms = new MemoryStream(content);
                mock.Setup(f => f.OpenReadStream()).Returns(ms);
                mock.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                    .Callback<Stream>(s => ms.CopyTo(s));
            }
            else
            {
                var ms = new MemoryStream(new byte[size > 0 ? size : 1]);
                mock.Setup(f => f.OpenReadStream()).Returns(ms);
                mock.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                    .Callback<Stream>(s => ms.CopyTo(s));
            }

            return mock.Object;
        }
    }
}

