using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from the static queue (shared across tests)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("TestUser", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Chemistry", notification.Message);
            Assert.Contains("Course", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Course", "101", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("101", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("created", notification.Message);
            Assert.Contains("John Doe", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultUser_SetsSystemAsCreatedBy()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_FIFOOrder()
        {
            _service.SendNotification("First", "1", EntityOperation.CREATE);
            _service.SendNotification("Second", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.NotNull(second);
            Assert.Equal("First", first.EntityType);
            Assert.Equal("Second", second.EntityType);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void MarkAsRead_WithAnyId_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(999));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName_Works()
        {
            _service.SendNotification("Instructor", "5", EntityOperation.UPDATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Instructor", notification.EntityType);
            Assert.Equal("5", notification.EntityId);
            Assert.Equal("UPDATE", notification.Operation);
        }

        [Fact]
        public void SendNotification_MultipleNotifications_AllEnqueued()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);
            _service.SendNotification("C", "3", EntityOperation.DELETE);

            var a = _service.ReceiveNotification();
            var b = _service.ReceiveNotification();
            var c = _service.ReceiveNotification();

            Assert.NotNull(a);
            Assert.NotNull(b);
            Assert.NotNull(c);
            Assert.Equal("A", a.EntityType);
            Assert.Equal("B", b.EntityType);
            Assert.Equal("C", c.EntityType);
        }
    }
}

using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        private static IList<ValidationResult> ValidateModel(object model)
        {
            var validationResults = new List<ValidationResult>();
            var ctx = new ValidationContext(model);
            Validator.TryValidateObject(model, ctx, validationResults, true);
            return validationResults;
        }

        #region Person / FullName

        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = DateTime.Now
            };

            Assert.Equal("Smith, John", student.FullName);
        }

        #endregion

        #region Student Validation

        [Fact]
        public void Student_ValidModel_PassesValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2020-01-15")
            };

            var results = ValidateModel(student);
            Assert.Empty(results);
        }

        [Fact]
        public void Student_MissingLastName_FailsValidation()
        {
            var student = new Student
            {
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2020-01-15")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_MissingFirstName_FailsValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                EnrollmentDate = DateTime.Parse("2020-01-15")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_LastNameTooLong_FailsValidation()
        {
            var student = new Student
            {
                LastName = new string('x', 51),
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2020-01-15")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstNameTooLong_FailsValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = new string('x', 51),
                EnrollmentDate = DateTime.Parse("2020-01-15")
