using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _controller = new StudentsController(_context);
            ControllerTestHelper.SetupController(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithPaginatedStudents()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_SortByNameDescending_ReturnsSortedStudents()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.True(model.Count > 0);
            // Should be descending by LastName
            for (int i = 0; i < model.Count - 1; i++)
            {
                Assert.True(string.Compare(model[i].LastName, model[i + 1].LastName, StringComparison.Ordinal) >= 0);
            }
        }

        [Fact]
        public void Index_SortByDateAscending_ReturnsSortedStudents()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            for (int i = 0; i < model.Count - 1; i++)
            {
                Assert.True(model[i].EnrollmentDate <= model[i + 1].EnrollmentDate);
            }
        }

        [Fact]
        public void Index_SortByDateDescending_ReturnsSortedStudents()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            for (int i = 0; i < model.Count - 1; i++)
            {
                Assert.True(model[i].EnrollmentDate >= model[i + 1].EnrollmentDate);
            }
        }

        [Fact]
        public void Index_DefaultSort_ReturnsSortedByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
