using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestDbContextFactory.CreateSeeded();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();

            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
            ControllerTestHelper.SetupController(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<IEnumerable<Course>>(result.Model);
            Assert.Equal(3, model.Count());
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var result = _controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", model.Title);
        }

        [Fact]
        public void Details_ValidId_IncludesDepartment()
        {
            var result = _controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.NotNull(model.Department);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewWithNewCourse()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_ValidCourseNoImage_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "NewCourse",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null!);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_ValidCourseNoImage_SavesCourseToDB()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "SavedCourse",
                Credits = 4,
                DepartmentID = 1
            };

            _controller.Create(course, null!);

            Assert.NotNull(_context.Courses.Find(8888));
        }

        [Fact]
        public void Create_WithValidImage_UploadsFileAndSaves()
        {
            var course = new Course
            {
                CourseID = 7777,
                Title = "ImageCourse",
                Credits = 3,
                DepartmentID = 1
            };
            var file = ControllerTestHelper.CreateMockFormFile("test.jpg", 1024);

            _controller.Create(course, file);

            var saved = _context.Courses.Find(7777);
            Assert.NotNull(saved);
            Assert.NotNull(saved.TeachingMaterialImagePath);
            Assert.StartsWith("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_WithInvalidExtension_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 6666,
                Title = "BadExtension",
                Credits = 3,
                DepartmentID = 1
            };
            var file = ControllerTestHelper.CreateMockFormFile("test.pdf", 1024);

            var result = _controller.Create(course, file) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_WithOversizedFile_ReturnsViewWithError()
        {
            var course = new Course
            {
                CourseID = 5555,
                Title = "BigFile",
                Credits = 3,
                DepartmentID = 1
            };
            var file = ControllerTestHelper.CreateMockFormFile("test.jpg", 6 * 1024 * 1024);

            var result = _controller.Create(course, file) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
