using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ModelTests
    {
        private static IList<ValidationResult> ValidateModel(object model)
        {
            var validationResults = new List<ValidationResult>();
            var ctx = new ValidationContext(model);
            Validator.TryValidateObject(model, ctx, validationResults, true);
            return validationResults;
        }

        #region Person / FullName

        [Fact]
        public void Person_FullName_ReturnsLastNameCommaFirstName()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = DateTime.Now
            };

            Assert.Equal("Smith, John", student.FullName);
        }

        #endregion

        #region Student Validation

        [Fact]
        public void Student_ValidModel_PassesValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2020-01-15")
            };

            var results = ValidateModel(student);
            Assert.Empty(results);
        }

        [Fact]
        public void Student_MissingLastName_FailsValidation()
        {
            var student = new Student
            {
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2020-01-15")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_MissingFirstName_FailsValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                EnrollmentDate = DateTime.Parse("2020-01-15")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        [Fact]
        public void Student_LastNameTooLong_FailsValidation()
        {
            var student = new Student
            {
                LastName = new string('x', 51),
                FirstMidName = "John",
                EnrollmentDate = DateTime.Parse("2020-01-15")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        [Fact]
        public void Student_FirstNameTooLong_FailsValidation()
        {
            var student = new Student
            {
                LastName = "Smith",
                FirstMidName = new string('x', 51),
                EnrollmentDate = DateTime.Parse("2020-01-15")
            };

            var results = ValidateModel(student);
            Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
        }

        #endregion

        #region Course Validation

        [Fact]
        public void Course_ValidModel_PassesValidation()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Empty(results);
        }

        [Fact]
        public void Course_TitleTooShort_FailsValidation()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "AB",
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_TitleTooLong_FailsValidation()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = new string('x', 51),
                Credits = 3,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Title"));
        }

        [Fact]
        public void Course_CreditsTooHigh_FailsValidation()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Chemistry",
                Credits = 6,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_CreditsNegative_FailsValidation()
        {
            var course = new Course
            {
                CourseID = 1001,
                Title = "Chemistry",
                Credits = -1,
                DepartmentID = 1
            };

            var results = ValidateModel(course);
            Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
        }

        [Fact]
        public void Course_CreditsAtBoundary_PassesValidation()
        {
            var course0 = new Course { CourseID = 1, Title = "Course0", Credits = 0, DepartmentID = 1 };
            var course5 = new Course { CourseID = 2, Title = "Course5", Credits = 5, DepartmentID = 1 };

            Assert.Empty(ValidateModel(course0));
            Assert.Empty(ValidateModel(course5));
        }

        #endregion

        #region Department Validation

        [Fact]
        public void Department_ValidModel_PassesValidation()
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            var results = ValidateModel(dept);
            Assert.Empty(results);
        }

        [Fact]
        public void Department_NameTooShort_FailsValidation()
        {
            var dept = new Department
            {
                Name = "AB",
                Budget = 350000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            var results = ValidateModel(dept);
            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        [Fact]
        public void Department_NameTooLong_FailsValidation()
        {
            var dept = new Department
            {
                Name = new string('x', 51),
                Budget = 350000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            var results = ValidateModel(dept);
            Assert.Contains(results, r => r.MemberNames.Contains("Name"));
        }

        #endregion

        #region Instructor Validation

        [Fact]
        public void Instructor_ValidModel_PassesValidation()
        {
            var instructor = new Instructor
            {
                LastName = "Smith",
                FirstMidName = "Jane",
                HireDate = DateTime.Parse("2020-01-15")
            };

            var results = ValidateModel(instructor);
            Assert.Empty(results);
        }

        [Fact]
        public void Instructor_MissingLastName_FailsValidation()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Jane",
                HireDate = DateTime.Parse("2020-01-15")
            };

            var results = ValidateModel(instructor);
            Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
        }

        #endregion

        #region Enrollment

        [Fact]
        public void Enrollment_GradeEnum_HasCorrectValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }

        [Fact]
        public void Enrollment_GradeIsNullable()
        {
            var enrollment = new Enrollment
            {
                CourseID = 1,
                StudentID = 1,
                Grade = null
            };

            Assert.Null(enrollment.Grade);
        }

        #endregion

        #region Notification

        [Fact]
        public void Notification_ValidModel_PassesValidation()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test message",
                CreatedAt = DateTime.Now,
                CreatedBy = "System"
            };

            var results = ValidateModel(notification);
            Assert.Empty(results);
        }

        [Fact]
        public void EntityOperation_HasCorrectValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        #endregion

        #region ErrorViewModel

        [Fact]
        public void ErrorViewModel_ShowRequestId_TrueWhenSet()
        {
            var model = new ErrorViewModel { RequestId = "abc123" };
            Assert.True(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenNull()
        {
            var model = new ErrorViewModel { RequestId = null };
            Assert.False(model.ShowRequestId);
        }

        [Fact]
        public void ErrorViewModel_ShowRequestId_FalseWhenEmpty()
        {
            var model = new ErrorViewModel { RequestId = "" };
            Assert.False(model.ShowRequestId);
        }

        #endregion

        #region OfficeAssignment

        [Fact]
        public void OfficeAssignment_LocationTooLong_FailsValidation()
        {
            var oa = new OfficeAssignment
            {
                InstructorID = 1,
                Location = new string('x', 51)
            };

            var results = ValidateModel(oa);
            Assert.Contains(results, r => r.MemberNames.Contains("Location"));
        }

        [Fact]
        public void OfficeAssignment_ValidLocation_PassesValidation()
        {
            var oa = new OfficeAssignment
            {
                InstructorID = 1,
                Location = "Smith 17"
            };

            var results = ValidateModel(oa);
            Assert.Empty(results);
        }

        #endregion

        #region CourseAssignment

        [Fact]
        public void CourseAssignment_HasExpectedProperties()
        {
            var ca = new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 100
            };

            Assert.Equal(1, ca.InstructorID);
            Assert.Equal(100, ca.CourseID);
        }

        #endregion
    }
}

