using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndexAndTotalPages()
        {
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 10, 2, 3);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_AddsAllItems()
        {
            var items = new List<string> { "a", "b", "c" };

            var list = new PaginatedList<string>(items, 3, 1, 3);

            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 5, 1, 5);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 1, 3);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void TotalPages_CalculatedCorrectly()
        {
            // 10 items, page size 3 = ceil(10/3) = 4
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 3);
            Assert.Equal(4, list.TotalPages);
        }

        [Fact]
        public void TotalPages_ExactDivision()
        {
            // 9 items, page size 3 = 3
            var list = new PaginatedList<int>(new List<int>(), 9, 1, 3);
            Assert.Equal(3, list.TotalPages);
        }

        [Fact]
        public void TotalPages_SingleItem()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);
            Assert.Equal(1, list.TotalPages);
        }

        [Fact]
        public void TotalPages_ZeroItems()
        {
            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);
            Assert.Equal(0, list.TotalPages);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var page1 = PaginatedList<int>.Create(source, 1, 10);
            var page2 = PaginatedList<int>.Create(source, 2, 10);
            var page3 = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(10, page1.Count);
            Assert.Equal(10, page2.Count);
            Assert.Equal(5, page3.Count);
            Assert.Equal(1, page1[0]);
            Assert.Equal(11, page2[0]);
            Assert.Equal(21, page3[0]);
        }

        [Fact]
        public void Create_SetsPaginationProperties()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.True(result.HasPreviousPage);
            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_FirstPage_NoPreviousPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.False(result.HasPreviousPage);
            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void Create_LastPage_NoNextPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.True(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }
    }
}

