using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestDbContextFactory.Create();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void Context_HasStudentsDbSet()
        {
            Assert.NotNull(_context.Students);
        }

        [Fact]
        public void Context_HasCoursesDbSet()
        {
            Assert.NotNull(_context.Courses);
        }

        [Fact]
        public void Context_HasDepartmentsDbSet()
        {
            Assert.NotNull(_context.Departments);
        }

        [Fact]
        public void Context_HasEnrollmentsDbSet()
        {
            Assert.NotNull(_context.Enrollments);
        }

        [Fact]
        public void Context_HasInstructorsDbSet()
        {
            Assert.NotNull(_context.Instructors);
        }

        [Fact]
        public void Context_HasOfficeAssignmentsDbSet()
        {
            Assert.NotNull(_context.OfficeAssignments);
        }

        [Fact]
        public void Context_HasCourseAssignmentsDbSet()
        {
            Assert.NotNull(_context.CourseAssignments);
        }

        [Fact]
        public void Context_HasNotificationsDbSet()
        {
            Assert.NotNull(_context.Notifications);
        }

        [Fact]
        public void Context_CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Parse("2020-01-15")
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First();
            Assert.Equal("Test", retrieved.LastName);
            Assert.Equal("Student", retrieved.FirstMidName);
        }

        [Fact]
        public void Context_CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "Test",
                FirstMidName = "Instructor",
                HireDate = DateTime.Parse("2020-01-15")
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First();
            Assert.Equal("Test", retrieved.LastName);
        }

        [Fact]
        public void Context_CanAddDepartmentWithCourses()
        {
            var dept = new Department
            {
                Name = "TestDept",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01")
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 9001,
                Title = "TestCourse",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
