using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsStudents()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
        }

        [Fact]
        public void Initialize_SeedsInstructors()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(5, context.Instructors.Count());
        }

        [Fact]
        public void Initialize_SeedsDepartments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(4, context.Departments.Count());
        }

        [Fact]
        public void Initialize_SeedsCourses()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(7, context.Courses.Count());
        }

        [Fact]
        public void Initialize_SeedsEnrollments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.True(context.Enrollments.Count() > 0);
        }

        [Fact]
        public void Initialize_SeedsOfficeAssignments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(3, context.OfficeAssignments.Count());
        }

        [Fact]
        public void Initialize_SeedsCourseAssignments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.CourseAssignments.Count());
        }

        [Fact]
        public void Initialize_DoesNotReseedIfDataExists()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);
            var initialCount = context.Students.Count();

            DbInitializer.Initialize(context);
            var afterCount = context.Students.Count();

            Assert.Equal(initialCount, afterCount);
        }

        [Fact]
        public void Initialize_CreatesCorrectStudentNames()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.True(context.Students.Any(s => s.LastName == "Alexander"));
            Assert.True(context.Students.Any(s => s.LastName == "Alonso"));
            Assert.True(context.Students.Any(s => s.LastName == "Olivetto"));
        }

        [Fact]
        public void Initialize_CreatesCorrectDepartmentNames()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.True(context.Departments.Any(d => d.Name == "English"));
            Assert.True(context.Departments.Any(d => d.Name == "Mathematics"));
            Assert.True(context.Departments.Any(d => d.Name == "Engineering"));
            Assert.True(context.Departments.Any(d => d.Name == "Economics"));
        }
    }
}

